import { jsxs, jsx } from 'react/jsx-runtime';
import { Typography } from '../../Typography/Typography.js';
import { classNames } from '../../../helpers/classnames.js';

const renderStateContent = (content) => typeof content === 'string' ? (jsx(Typography, { variant: "body2", inactive: true, children: content })) : (content);
const DropdownList = ({ loading = false, loadingContent, empty = false, emptyContent, headerContent, footerContent, maxHeight, children, className, style, dataTestId = 'DropdownList', ...props }) => {
    const scrollStyle = maxHeight ? { ...style, maxHeight: `${maxHeight}px` } : style;
    const renderBody = () => {
        if (loading) {
            return (jsx("div", { className: "dsb_dropdown-list__state", "data-testid": dataTestId + '-loading', children: renderStateContent(loadingContent ?? 'Загрузка…') }));
        }
        if (empty) {
            return (jsx("div", { className: "dsb_dropdown-list__state", "data-testid": dataTestId + '-empty', children: renderStateContent(emptyContent ?? 'Нет результатов') }));
        }
        return children;
    };
    return (jsxs("div", { className: classNames('dsb_dropdown-list', className), "data-testid": dataTestId, ...props, children: [headerContent && jsx("div", { className: "dsb_dropdown-list__header", children: headerContent }), jsx("div", { className: "dsb_dropdown-list__scroll", role: "listbox", style: scrollStyle, children: renderBody() }), footerContent && jsx("div", { className: "dsb_dropdown-list__footer", children: footerContent })] }));
};

export { DropdownList };
